import{c as a,bn as e,aU as r,aX as d,n as l,V as h,ah as n,as as i}from"./chunks/framework.EkwLm6yr.js";const y=JSON.parse('{"title":"时间","description":"","frontmatter":{"order":4},"headers":[],"relativePath":"地图/北俱芦洲/时间.md","filePath":"地图/北俱芦洲/时间.md","lastUpdated":1779731263000}'),s={name:"地图/北俱芦洲/时间.md"};function o(b,t,c,m,x,p){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="时间" tabindex="-1">时间 <a class="header-anchor" href="#时间" aria-label="Permalink to “时间”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">葫芦藓</td><td style="text-align:center;">碎陨星</td><td style="text-align:center;">流光绸</td></tr></tbody></table><h2 id="夙夜径" tabindex="-1">夙夜径 <a class="header-anchor" href="#夙夜径" aria-label="Permalink to “夙夜径”">​</a></h2><h3 id="场景" tabindex="-1">场景 <a class="header-anchor" href="#场景" aria-label="Permalink to “场景”">​</a></h3><p>会随着时间（观察眼睛）切换昼夜，<strong>攻击雕像嘴中的珠子</strong>可获得光源</p><img src="'+l+'" alt="夙夜径场景" style="zoom:67%;"><h3 id="角木蛟" tabindex="-1">角木蛟 <a class="header-anchor" href="#角木蛟" aria-label="Permalink to “角木蛟”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>蛟龙突击：伸长长枪向玩家方向突刺</td></tr><tr><td>木蛟之影：将枪刺入地面，地面长出木藤呈龙形向前移动，碰触到玩家后将其束缚</td></tr><tr><td>棘刺之木：在地面随机一处召唤一株卷曲的长刺灌木，攻击灌木会受到伤害</td></tr><tr><td>灭世双蛟：从脚下出现两只木龙盘旋缠绕升起，飞出屏幕顶端，之后从玩家头顶上方落下</td></tr><tr><td>蛟临天下：脚下生成一株小树，BOSS跃至树上；BOSS在树上时处于霸体状态，并持续恢复生命，且会不断向玩家投掷长枪；树可以被破坏，树破坏后BOSS将落回地面解除状态</td></tr></tbody></table><p>掉落道具：烛时防具制作书</p><h2 id="太虚星河" tabindex="-1">太虚星河 <a class="header-anchor" href="#太虚星河" aria-label="Permalink to “太虚星河”">​</a></h2><h3 id="场景-1" tabindex="-1">场景 <a class="header-anchor" href="#场景-1" aria-label="Permalink to “场景”">​</a></h3><p>星河流动，使站在地上角色缓慢向屏幕左侧移动</p><img src="'+h+'" alt="太虚星河场景" style="zoom:50%;"><h3 id="应龙·鼓" tabindex="-1">应龙·鼓 <a class="header-anchor" href="#应龙·鼓" aria-label="Permalink to “应龙·鼓”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>灭神龙爪：手化为巨大龙，攻击周身玩家</td></tr><tr><td>星流之翼：煽动双翼，向玩家方法射出2道交叉缠绕的流星</td></tr><tr><td>噬星龙爪：手化为巨大龙爪，急速飞向玩家后将其擒住，缓慢抽取魔法；此时玩家无法移动、跳跃、使用技能，玩家需通过对BOSS造成一定伤害，解除该状态</td></tr><tr><td>毁灭星核：在一定范围内召唤3颗星核，星核会在5秒后化为流星射向玩家</td></tr><tr><td>斗转星移：用双翼和星辰包裹身体，此时所受的任何伤害都将被吸收并转化为生命回复</td></tr></tbody></table><p>掉落道具：烛时武器制作书（第一心法）</p><h2 id="太虚星河隐藏" tabindex="-1">太虚星河隐藏 <a class="header-anchor" href="#太虚星河隐藏" aria-label="Permalink to “太虚星河隐藏”">​</a></h2><p>点按D键<strong>保持</strong>在划框处位置，可进入<strong>隐藏关卡</strong>（开坐骑可以获得霸体）</p><img src="'+n+'" alt="太虚星河隐藏" style="zoom:67%;"><h3 id="女魃" tabindex="-1">女魃 <a class="header-anchor" href="#女魃" aria-label="Permalink to “女魃”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>旱魃为虐：持续施法，链接周身的目标持续抽取生命，目标离开区域或5秒后方可解除。</td></tr><tr><td>众生聚灭：持续施法，出现蓝色流火吸向女魃，玩家碰触流火后会被带往BOSS处</td></tr><tr><td>焚天流火：高举法杖，向四面八方发射数道红色流火</td></tr><tr><td>噬魔火灵：从法杖中召唤1个蓝色火灵。每当玩家使用技能，蓝灵会吸取玩家10%的魔法</td></tr><tr><td>噬血火灵：从法杖中召唤1个红色火灵。每当玩家受到伤害，红灵会吸取玩家10%的生命</td></tr></tbody></table><p>掉落道具：烛时武器制作书（第二心法）</p><h2 id="钟晷极地" tabindex="-1">钟晷极地 <a class="header-anchor" href="#钟晷极地" aria-label="Permalink to “钟晷极地”">​</a></h2><h3 id="时间祖巫" tabindex="-1">时间祖巫 <a class="header-anchor" href="#时间祖巫" aria-label="Permalink to “时间祖巫”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>拍击：用爪子拍打地面，攻击近身的玩家</td></tr><tr><td>摆尾：摆动尾巴，攻击周身的玩家</td></tr><tr><td>嘘为风影：深吸一口气，从屏幕边缘出现数道龙影，如同疾风一般冲向玩家</td></tr><tr><td>吹为雷火：深吐一口气，一道火柱从口中喷发而出，横扫地面</td></tr><tr><td>逆时之烛-年轻：召唤逆时之烛，使时光逆转，持续恢复烛龙的生命（烛火每秒减少5%的生命，当烛火燃尽时效果消失。攻击烛火可以加快烛火的燃烧速度）</td></tr><tr><td>静时之烛：召唤静时之烛，当烛火燃尽时，将会冻结玩家的时间数秒（烛火每秒减少2.5%的生命，当烛火燃尽时效果消失。攻击烛火可以加快烛火的燃烧速度）</td></tr><tr><td>幽阴之眼：闭上眼睛，全屏变成黑夜，伸手不见五指（在黑暗的区域，玩家的命中大幅下降）</td></tr><tr><td>顺时之烛-衰老：顺时之烛受到一定的攻击后，烛火将会点亮，黑暗将被照亮，但玩家生命也会随着烛火缓缓流逝。（烛火每秒减少2.5%的生命，当烛火燃尽时效果消失，但数秒后会重新出现。攻击烛火可以加快烛火的燃烧速度）</td></tr></tbody></table><p>掉落道具：<a href="/zmxy4-helpPages/饰品/常见主线饰品.html#烛时玉带">烛时玉带制作书</a></p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="烛时金轮" tabindex="-1">烛时金轮 <a class="header-anchor" href="#烛时金轮" aria-label="Permalink to “烛时金轮”">​</a></h3><img src="'+i+'" alt="烛时金轮" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">8~11</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">5~7</td></tr></tbody></table>',31)])])}const g=a(s,[["render",o]]);export{y as __pageData,g as default};
